mapper.select:
select CONCAT(CONVERT(varchar(10),a.pur_order_date,23),' - ',a.seq) AS purOrderDateSeq ,a.pur_order_date ,a.delivery_date ,dbo.getCustomerName(a.customer_cd) as customer_name ,b.item_cd ,b.item_name ,dbo.getStorageName(a.storage_cd) as storageName ,b.qty ,b.spec ,0 as inQty ,b.supply_price ,b.in_price ,b.vat_price ,b.item_type_cd ,case when b.in_yn = 'Y' then '입고완료'else '미입고' end inYn ,case when a.end_yn = 'Y' then '종결'else '진행중' end endYn ,case when a.mail_yn = 'Y' then '발송'else '미발송' end mailYn ,dbo.getUserName(a.manager_id) as manager_name ,a.pur_order_id ,b.pur_order_item_id from tb_pur_order_mst a inner join tb_pur_order_item b on a.pur_order_id = b.pur_order_id where 1=1
and a.pur_order_date between #{strDate} and #{endDate}
and a.area_cd = #{areaCd}
and b.item_type_cd = #{itemTypeCd}
and b.item_cd like '%' + #{itemCd} + '%'
and b.item_name like '%' + #{itemName} + '%'
and dbo.getCustomerName(a.customer_cd) like '%' + #{customerName} + '%'
and b.in_yn = #{inYn}
and a.end_yn = #{endYn}
order by a.pur_order_date desc, a.seq desc

SELECT CONCAT(CONVERT(varchar(10),a.pur_order_date,23),' - ',a.seq) AS purOrderDateSeq ,a.pur_order_date ,CASE WHEN COUNT(b.item_cd) = 1 THEN MIN(b.item_name) ELSE MIN(b.item_name) + ' 외 ' + CAST(COUNT(b.item_cd) - 1 AS VARCHAR) + '건' END AS item_name ,dbo.getCustomerName(a.customer_cd) AS customer_Name ,a.storage_cd ,SUM(b.qty) AS totQty ,SUM(b.in_price) AS totPrice ,sum(b.supply_Price) as supplyPrice ,a.delivery_date ,dbo.getStorageName(a.storage_cd) AS storage_name ,CASE WHEN a.end_yn = 'Y' THEN '종결' ELSE '진행중' END AS endYn ,CASE WHEN a.mail_yn = 'Y' THEN '발송' ELSE '미발송' END AS mailYn ,dbo.getUserName(a.manager_id) AS manager_name ,a.pur_order_id FROM tb_pur_order_mst a INNER JOIN tb_pur_order_item b ON a.pur_order_id = b.pur_order_id where b.item_type_cd in ('M2', 'M7')
and a.pur_order_date between #{strDate} and #{endDate}
and b.area_cd = #{areaCd}
and a.item_cd = #{itemCd}
and b.item_name like '%' + #{itemName} + '%'
and dbo.getCustomerName(a.customer_cd) like '%' + #{customerName} + '%'
and a.end_yn = #{endYn}
GROUP BY a.pur_order_date, a.seq, a.customer_cd, a.delivery_date, a.storage_cd, a.end_yn, a.mail_yn, a.manager_id, a.pur_order_id order by a.pur_order_date desc, a.seq desc

select a.item_cd ,a.item_name ,a.item_type_cd ,a.spec ,a.qty ,a.in_price ,a.supply_price ,a.vat_price ,a.etc ,a.in_yn ,a.pur_order_id ,a.pur_order_item_id from tb_pur_order_item a where
a.pur_order_item_id = #{purOrderId}
a.pur_order_id = #{purOrderId}

