      , item_type_cd    = #{itemTypeCd}
      , spec            = #{spec}
      , qty             = #{qty}
      , in_price        = #{inPrice}
      , supply_price    = #{supplyPrice}
      , vat_price       = #{vatPrice}
      , etc             = #{etc}
      , upd_id          = #{userId}
      , upd_dt          = getDate()
